import{_ as e,c as a,a as n,o as i}from"./app-CEcM0piI.js";const t={};function d(p,s){return i(),a("div",null,s[0]||(s[0]=[n(`<p>SpringData是Spring中数据操作的模块，包含对各种数据库的集成，其其中对Redis的集成模块就叫做SpringDataRedis</p><h4 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  data:</span></span>
<span class="line"><span>    redis:</span></span>
<span class="line"><span>      host: localhost</span></span>
<span class="line"><span>      port: 6379</span></span>
<span class="line"><span>      password: &quot;03604&quot;</span></span>
<span class="line"><span>      lettuce:</span></span>
<span class="line"><span>        pool:</span></span>
<span class="line"><span>          max-active: 8 # 最大连接</span></span>
<span class="line"><span>          max-idle:  8 # 最大空闲连接</span></span>
<span class="line"><span>          min-idle: 0 # 最小空闲连接</span></span>
<span class="line"><span>          max-wait: 100 # 连接等待时间</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>SpringDataRedis中提供了RedisTemplate了各种对ReOIs的操作.：并且将不同数据类型的操作API封装到了不同的类型中：</p><table><thead><tr><th>API</th><th>返回值</th><th>类型说明</th></tr></thead><tbody><tr><td>redisTemplate.opsForValue()</td><td>ValueOperations</td><td>操作String类型数据</td></tr><tr><td>redisTemplate.opsForHash()</td><td>HashOperations</td><td>操作Hash类型数据</td></tr><tr><td>redisTemplate.opsForList()</td><td>ListOperations</td><td>操作List类型数据</td></tr><tr><td>redisTemplate.opsForSet()</td><td>SetOperations</td><td>操作Set类型数据</td></tr><tr><td>redisTemplate.opsForZSet()</td><td>ZSetOperations</td><td>操作SortedSet类型数据</td></tr><tr><td>redisTemplate</td><td></td><td>通用的命令</td></tr><tr><td>示例:</td><td></td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootTest</span></span>
<span class="line"><span>class DemoApplicationTests {</span></span>
<span class="line"><span>	@Autowired</span></span>
<span class="line"><span>	private RedisTemplate&lt;String,Object&gt; redisTemplate;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	@Test</span></span>
<span class="line"><span>	void testString(){</span></span>
<span class="line"><span>		redisTemplate.opsForValue().set(&quot;name&quot;,&quot;zhangsan&quot;);</span></span>
<span class="line"><span>		System.out.println(redisTemplate.opsForValue().get(&quot;name&quot;));</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但设置数据后再次查询name键,如果之前没有name就查询不到数据,如果之前有name键那么查询到的是旧的数据而不是新插入的</p><p>RedisTemplate可以接收任意Object作为值写入Redis，只不过写入前会把Object序列化为字节形式，默认是采用JDK序列化，得到的结果是这样的：<code>\\xAC\\xED\\x00\\x05t\\x00\\x04name</code> 这种方法可读性差且内存占用较大</p><p>可以自己指定序列化器,不使用jdk的序列化器</p>`,9)]))}const r=e(t,[["render",d]]),c=JSON.parse('{"path":"/tools/redis/5/","title":"5 SpringDataRedis","lang":"zh-CN","frontmatter":{"title":"5 SpringDataRedis","createTime":"2025/04/05 12:12:26","permalink":"/tools/redis/5/"},"readingTime":{"minutes":1.17,"words":351},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/Redis/5 SpringDataRedis.md","headers":[]}');export{r as comp,c as data};
